mapper.select:
SELECT b.id, b.member_id AS memberId, b.title, b.content, m.nickname AS nickName, b.created_at AS createdAt, b.modified_at AS modifiedAt, b.view_count AS viewCount, b.category, b.is_notice AS isNotice, b.file_path AS filePath FROM board b INNER JOIN member m ON b.member_id = m.id
AND b.category = #{pageDto.category}
ORDER BY b.is_notice DESC, b.view_count DESC, b.id DESC
ORDER BY b.is_notice DESC, b.created_at DESC, b.id DESC
LIMIT #{pageDto.pageSize} OFFSET #{pageDto.offset}
